# Integrating Claude into Next.js with Streaming

Here's the simplest approach using the Anthropic SDK:

## 1. Install Dependencies

```bash
npm install @anthropic-ai/sdk
```

## 2. Create an API Route

Create `app/api/chat/route.ts`:

```typescript
import Anthropic from "@anthropic-ai/sdk";
import { NextRequest, NextResponse } from "next/server";

const client = new Anthropic();

export async function POST(request: NextRequest) {
  const { message } = await request.json();

  const stream = await client.messages.stream({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 1024,
    messages: [
      {
        role: "user",
        content: message,
      },
    ],
  });

  // Convert to ReadableStream for Next.js streaming
  const encoder = new TextEncoder();
  const readableStream = new ReadableStream({
    async start(controller) {
      for await (const chunk of stream) {
        if (
          chunk.type === "content_block_delta" &&
          chunk.delta.type === "text_delta"
        ) {
          controller.enqueue(encoder.encode(chunk.delta.text));
        }
      }
      controller.close();
    },
  });

  return new NextResponse(readableStream, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
    },
  });
}
```

## 3. Create a Client Component

Create `components/ChatBox.tsx`:

```typescript
"use client";

import { useState } from "react";

export default function ChatBox() {
  const [message, setMessage] = useState("");
  const [response, setResponse] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setResponse("");

    try {
      const res = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message }),
      });

      const reader = res.body?.getReader();
      const decoder = new TextDecoder();

      while (true) {
        const { done, value } = await reader!.read();
        if (done) break;

        const text = decoder.decode(value);
        setResponse((prev) => prev + text);
      }
    } catch (error) {
      console.error("Error:", error);
    } finally {
      setLoading(false);
      setMessage("");
    }
  };

  return (
    <div className="flex flex-col gap-4">
      <form onSubmit={handleSubmit} className="flex gap-2">
        <input
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          placeholder="Ask a question..."
          className="flex-1 px-4 py-2 border rounded"
          disabled={loading}
        />
        <button
          type="submit"
          disabled={loading}
          className="px-6 py-2 bg-blue-500 text-white rounded disabled:opacity-50"
        >
          {loading ? "..." : "Send"}
        </button>
      </form>
      {response && (
        <div className="p-4 bg-gray-100 rounded whitespace-pre-wrap">
          {response}
        </div>
      )}
    </div>
  );
}
```

## 4. Set Environment Variable

Add to `.env.local`:

```
ANTHROPIC_API_KEY=your_key_here
```

Get your API key from [console.anthropic.com](https://console.anthropic.com).

## Key Features of This Setup

- ✅ **Real-time streaming** - Response appears as it's generated
- ✅ **Minimal code** - ~40 lines total
- ✅ **Type-safe** - Full TypeScript support
- ✅ **No dependencies** - Just the official SDK
- ✅ **Works with user data** - Easy to add context to messages

